<script setup lang="ts">import{computed,ref}from'vue';import{useMutation,useQuery,useQueryClient}from'@tanstack/vue-query';import{FileCode2,Play,Plus,RefreshCw,ShieldCheck,SquareMinus,TriangleAlert}from'lucide-vue-next';import Button from'@/components/ui/Button.vue';import StatusBadge from'@/components/ui/StatusBadge.vue';import{getTerraformRuns,startTerraformRun}from'@/lib/api_terraform';const client=useQueryClient();const query=useQuery({queryKey:['terraform-runs'],queryFn:getTerraformRuns,refetchInterval:5000});const workspace=ref('');const mutation=useMutation({mutationFn:(operation:'validate'|'plan')=>startTerraformRun(operation,workspace.value),onSuccess:()=>client.invalidateQueries({queryKey:['terraform-runs']})});const runs=computed(()=>query.data.value?.items??[]);const latest=computed(()=>runs.value[0]);const run=(operation:'validate'|'plan')=>{if(workspace.value)mutation.mutate(operation)};</script>
<template><div class="mx-auto max-w-[1500px] space-y-5"><header><div class="flex gap-2"><StatusBadge status="healthy" label="ephemeral worker"/><span class="inline-flex items-center gap-1.5 font-mono text-[10px] uppercase text-signal"><ShieldCheck class="h-3.5 w-3.5"/>typed operations only</span></div><h1 class="mt-4 text-3xl font-semibold">Terraform plans</h1><p class="mt-2 text-sm text-muted">Validate e plan executados fora da API, em worker efêmero com workspaces allowlisted.</p></header><section class="rounded-xl border border-line bg-panel/65 p-5"><div class="grid gap-4 md:grid-cols-[1fr_auto_auto]"><label class="text-xs text-muted">Workspace<select v-model="workspace" class="field"><option value="" disabled>Selecione um workspace</option><option v-for="item in query.data.value?.workspaces" :key="item" :value="item">{{item}}</option></select></label><Button class="self-end" variant="outline" :disabled="!workspace||mutation.isPending.value" @click="run('validate')"><FileCode2 class="h-4 w-4"/>Validate</Button><Button class="self-end" :disabled="!workspace||mutation.isPending.value" @click="run('plan')"><Play class="h-4 w-4"/>Plan</Button></div><p v-if="mutation.isError.value" class="mt-4 text-xs text-danger">O worker recusou a solicitação. Confirme workspace e credenciais efêmeras.</p></section><section v-if="latest" class="grid gap-3 sm:grid-cols-3"><article class="rounded-xl border border-signal/20 bg-signal/[.04] p-5"><Plus class="h-4 w-4 text-signal"/><p class="mt-4 font-mono text-3xl">{{latest.summary.add}}</p><p class="text-xs text-muted">To add</p></article><article class="rounded-xl border border-warning/20 bg-warning/[.04] p-5"><RefreshCw class="h-4 w-4 text-warning"/><p class="mt-4 font-mono text-3xl">{{latest.summary.change}}</p><p class="text-xs text-muted">To change</p></article><article class="rounded-xl border border-danger/20 bg-danger/[.04] p-5"><SquareMinus class="h-4 w-4 text-danger"/><p class="mt-4 font-mono text-3xl">{{latest.summary.destroy}}</p><p class="text-xs text-muted">To destroy</p></article></section><section class="grid gap-5 xl:grid-cols-[380px_1fr]"><aside class="overflow-hidden rounded-xl border border-line bg-panel/65"><header class="border-b border-line p-4"><h2 class="text-sm font-medium">Run history</h2></header><div class="divide-y divide-line/60"><button v-for="item in runs" :key="item.id" class="w-full cursor-pointer p-4 text-left hover:bg-white/[.02]"><div class="flex items-center gap-2"><p class="flex-1 text-sm text-slate-200">{{item.workspace}}</p><StatusBadge :status="item.status==='succeeded'?'healthy':item.status==='failed'?'critical':'info'" :label="item.status"/></div><p class="mt-2 font-mono text-[9px] uppercase text-muted">{{item.operation}} · {{new Date(item.created_at).toLocaleString('pt-BR')}}</p></button><p v-if="!runs.length" class="p-10 text-center text-xs text-muted">Nenhuma execução.</p></div></aside><article class="min-h-96 rounded-xl border border-line bg-[#070b13] p-5"><div class="flex items-center gap-2"><TriangleAlert v-if="latest?.summary.destroy" class="h-4 w-4 text-danger"/><FileCode2 v-else class="h-4 w-4 text-signal"/><h2 class="text-sm font-medium">Redacted plan output</h2></div><pre class="mt-5 max-h-[560px] overflow-auto whitespace-pre-wrap break-words font-mono text-[11px] leading-5 text-slate-400">{{latest?.output||'Execute validate ou plan para visualizar a saída redigida do worker.'}}</pre></article></section></div></template>
